import Foundation

enum Arcana: String, Codable {
    case major
    case minor
}

enum Suit: String, Codable {
    case wands
    case cups
    case swords
    case pentacles
}

struct TarotCard: Identifiable, Codable {
    let id: Int
    let name: String
    let arcana: Arcana
    let suit: Suit?
    let number: String
    let uprightMeaning: String
    let reversedMeaning: String
    let keywords: [String]
    let symbolism: String
    let symbolName: String  // SF Symbol name — replaces emoji

    var suitSymbolName: String {
        switch suit {
        case .wands: return "flame"
        case .cups: return "drop.fill"
        case .swords: return "wind"
        case .pentacles: return "leaf.fill"
        case .none: return "sparkle"
        }
    }
}

// MARK: - Full 78-Card Deck

extension TarotCard {
    static let deck: [TarotCard] = majorArcana + minorArcanaWands + minorArcanaCups + minorArcanaSwords + minorArcanaPentacles

    // MARK: Major Arcana (22 cards)
    static let majorArcana: [TarotCard] = [
        TarotCard(id: 0, name: "The Fool", arcana: .major, suit: nil, number: "0",
