        TarotCard(id: 69, name: "Six of Pentacles", arcana: .minor, suit: .pentacles, number: "6",
            uprightMeaning: "A wealthy merchant with balanced scales distributes coins to kneeling beggars. The Six of Pentacles is the card of generosity and fair exchange — of giving and receiving in right proportion. Resources are flowing; the question is whether you are in the role of giver, receiver, or the scale itself.",
            reversedMeaning: "An imbalance of giving and receiving. Either generosity has strings attached and functions as control, or receiving is tinged with resentment and loss of dignity. True exchange requires that both parties maintain their wholeness in the transaction.",
            keywords: ["generosity", "charity", "giving and receiving", "fairness"],
            symbolism: "A prosperous merchant holds balanced scales and distributes coins to two kneeling figures — the circulation of wealth in right measure.",
            symbolName: "leaf.fill"),
        TarotCard(id: 70, name: "Seven of Pentacles", arcana: .minor, suit: .pentacles, number: "7",
            uprightMeaning: "A farmer leans on his hoe and contemplates the seven pentacles growing on the bush he has been tending. The Seven of Pentacles is the mid-point assessment — the pause in the middle of the long work to evaluate whether the effort is yielding the expected fruit. Patience and honest evaluation are both required.",
            reversedMeaning: "Impatience or misaligned effort is threatening the harvest. Either you are abandoning what you planted before it had time to mature, or you are pouring energy into something that genuinely will not yield what you hoped. Discernment between patience and delusion is the task.",
            keywords: ["patience", "investment", "assessment", "long-term vision"],
            symbolism: "A weary farmer leans on his hoe and studies the seven pentacle-fruits growing from the bush of his long labour.",
            symbolName: "leaf.fill"),
        TarotCard(id: 71, name: "Eight of Pentacles", arcana: .minor, suit: .pentacles, number: "8",
            uprightMeaning: "A young craftsman carves pentacles with total absorption, six finished on a pole beside him, two more to complete. The Eight of Pentacles is the deep satisfaction of skilled work — of becoming excellent through the practice of the same thing many times until mastery emerges almost without noticing. Dedication is its own reward.",
            reversedMeaning: "Perfectionism has stalled productivity, or work is being performed mechanically without the engaged attention that produces quality. Either the standards have become unreachable, or the work has become disconnected from meaning. Find the joy in the making again.",
            keywords: ["diligence", "craftsmanship", "skill development", "mastery"],
            symbolism: "A focused craftsman carves pentacle after pentacle at his bench, surrounded by evidence of his patient, accumulating skill.",
            symbolName: "leaf.fill"),
        TarotCard(id: 72, name: "Nine of Pentacles", arcana: .minor, suit: .pentacles, number: "9",
            uprightMeaning: "A woman in a golden vineyard with a falcon on her gloved wrist walks among her abundance with complete poise and independence. The Nine of Pentacles is the achievement of material self-sufficiency — the elegant enjoyment of what has been created through one's own sustained effort. You have earned this.",
            reversedMeaning: "Financial independence is being undermined by dependency, poor decisions, or the substitution of material comfort for genuine fulfilment. The garden is beautiful, but something essential is absent. What has been sacrificed in the pursuit of security?",
            keywords: ["abundance", "self-sufficiency", "independence", "luxury"],
            symbolism: "A poised woman strolls a private vineyard with a trained falcon — the picture of graceful, self-made abundance.",
            symbolName: "leaf.fill"),
        TarotCard(id: 73, name: "Ten of Pentacles", arcana: .minor, suit: .pentacles, number: "10",
            uprightMeaning: "An old patriarch in a patterned robe sits beneath a decorated archway, grandchildren at play, dogs at his feet, his adult children behind him. The Ten of Pentacles is legacy — the material and spiritual wealth that extends across generations, the sense of having built something that will outlast you.",
            reversedMeaning: "Family conflict over money or legacy is creating instability. The structure of material security has cracks — either in the foundation or in the relationships that hold it. What has been built together is being pulled apart by competing claims or unspoken resentments.",
            keywords: ["legacy", "family wealth", "stability", "inheritance"],
            symbolism: "An elder surrounded by grandchildren and dogs sits beneath an archway of coins — the portrait of a life that has made itself permanent.",
            symbolName: "leaf.fill"),
        TarotCard(id: 74, name: "Page of Pentacles", arcana: .minor, suit: .pentacles, number: "Page",
            uprightMeaning: "A young figure in a green field holds up a pentacle and studies it with complete concentration. The Page of Pentacles is the student of the material world — earnest, methodical, and deeply interested in how things actually work. This is the energy of new skills being learned with genuine seriousness.",
            reversedMeaning: "Lack of focus or follow-through on practical matters. Interesting ideas remain perpetually at the study stage, never reaching the execution phase. Or, materialism without wisdom — the interest in wealth without the values that would make that wealth meaningful.",
            keywords: ["studiousness", "ambition", "new skills", "practicality"],
            symbolism: "A contemplative youth in a blooming field holds a pentacle aloft, studying it with the complete attention of a first encounter.",
            symbolName: "leaf.fill"),
        TarotCard(id: 75, name: "Knight of Pentacles", arcana: .minor, suit: .pentacles, number: "Knight",
            uprightMeaning: "A fully armed knight sits on a dark horse in a cultivated field, holding a pentacle and surveying the terrain with patient deliberation. Unlike the other knights, he is entirely still — because he knows that this ground requires not speed but steadiness. Methodical progress is his gift and his power.",
            reversedMeaning: "Stubbornness masquerades as steadiness, or the methodical approach has become stuck in the mud of routine. The responsible work ethic has calcified into a refusal to adapt. Something new is being resisted not from wisdom but from inertia.",
            keywords: ["reliability", "persistence", "efficiency", "conservatism"],
            symbolism: "A dark-armored knight sits perfectly still on a powerful horse in a tilled field, holding a single pentacle with total attentiveness.",
            symbolName: "leaf.fill"),
        TarotCard(id: 76, name: "Queen of Pentacles", arcana: .minor, suit: .pentacles, number: "Queen",
            uprightMeaning: "She sits on a flower-carved throne in a green bower with a rabbit at her feet, cradling a pentacle in her lap with the ease of long familiarity. The Queen of Pentacles has created a world of practical abundance — a home that nourishes, a life that sustains, a generosity that flows from her own deep rootedness in what actually matters.",
            reversedMeaning: "Over-focus on material security at the expense of emotional or spiritual nourishment, or the practical care has become suffocating control. Alternatively, financial mismanagement or neglect of the material dimension of life is creating instability.",
            keywords: ["nurturing", "practical", "resourceful", "grounded"],
            symbolism: "A richly robed queen cradles a golden pentacle in her lush garden throne while a nimble hare keeps her company.",
            symbolName: "leaf.fill"),
        TarotCard(id: 77, name: "King of Pentacles", arcana: .minor, suit: .pentacles, number: "King",
            uprightMeaning: "A king enthroned in a garden overgrown with vines and grapes, his armor covered with bull motifs, a scepter in one hand and a pentacle in the other. The King of Pentacles has built a kingdom on the patient accumulation of real value — he is the master of the material world because he has respected it, not exploited it.",
            reversedMeaning: "Materialism without wisdom, or the misuse of accumulated power. Financial stubbornness is creating problems, or wealth is being used to control others. The king who confuses his kingdom for himself has already begun the process of losing both.",
            keywords: ["financial mastery", "abundance", "reliability", "security"],
            symbolism: "A powerful king seated in a castle garden, his every surface adorned with the symbols of abundance — vines, bulls, pentacles, and gold.",
            symbolName: "leaf.fill")
    ]
}
